  'ppl-ch16-l2': {
    headline: 'Wake Turbulence — Vortex Generation, Avoidance & ATC',
    explanation: 'Wake turbulence is generated by all aircraft in flight as a result of lift production. The wingtip vortices are most intense behind heavy, slow, clean (flaps up) aircraft. Vortices sink at about 300–500 ft per minute and drift with the wind. Light aircraft following heavy aircraft are most at risk — especially on approach and departure. ATC separation standards exist, but pilots must apply their own conservative judgment.',
    references: { phak: 'Chapter 5: Aerodynamics / Chapter 14: Airport Operations', aim: 'AIM 7-3' },
    keyFacts: [
      { fact: 'Vortices most intense: heavy, slow, clean configuration', detail: 'Maximum lift = maximum vortex strength. On final approach, a large jet flaps-up at slow speed is most dangerous.' },
      { fact: 'Vortices sink 300–500 fpm and drift with wind', detail: 'A crosswind can hold one vortex over the runway while the other drifts away. In calm conditions, vortices stay on the runway centerline.' },
      { fact: 'Takeoff behind heavy: rotate before heavy\'s rotation point, climb above its climb path', detail: 'Vortices trail from the rotation point. If you rotate early and climb steeply, you stay above the vortex.' },
      { fact: 'Landing behind heavy: land beyond the heavy\'s touchdown point', detail: 'Vortices trail the heavy from its touchdown point rearward. Landing long (past the heavy) avoids them.' },
    ],
    faaTestTips: [
      '"When are wingtip vortices most severe?" — Heavy aircraft, slow speed, clean configuration (flaps up).',
      '"On a calm-wind day, where do vortices from a preceding jet go?" — They sink and drift outward from the centerline, approximately 300–500 fpm.',
      '"You are landing behind a heavy jet on the same runway. Where should you touch down?" — Beyond the heavy\'s touchdown point.',
    ],
    selfTest: [
      { question: 'What type of aircraft generates the most intense wake turbulence?', answer: 'Heavy aircraft at slow speeds with clean configuration (flaps retracted) — maximum lift = maximum vortex strength.' },
      { question: 'On a no-wind day, where do wingtip vortices go after a departing heavy aircraft?', answer: 'They sink 300–500 fpm and drift outward from the runway centerline — remaining roughly over the runway for several minutes.' },
      { question: 'How should you avoid wake turbulence when departing behind a heavy jet?', answer: 'Rotate before the heavy\'s rotation point and climb above and upwind of its departure path.' },
    ],
  },

